const data = JSON.parse($json.stdout);

return [
  {
    json: {
      texto: data.texto
    }
  }
];

let texto = $json.texto;

// junta linhas quebradas
texto = texto.replace(/-\n/g, '');
texto = texto.replace(/\n+/g, '\n');

// remove espaços duplicados
texto = texto.replace(/[ \t]+/g, ' ');

// remove lixo isolado
texto = texto.replace(/\n[^\wÀ-ÿ]{1,3}\n/g, '\n');

return [
  {
    json: {
      texto_limpo: texto
    }
  }
];
